interface.definition:
a!localVariables(
  local!contacts: {
    a!map(
      id: 1,
      name: "Opa Olaf",
      number: "+49 123456789",
      image: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1071649"
    ),
    a!map(
      id: 2,
      name: "Ehefrau Eva",
      number: "+49 123456789",
      image: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1071661"
    ),
    a!map(
      id: 3,
      name: "Papa Paul",
      number: "+49 123456789",
      image: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1071643"
    ),
    a!map(
      id: 4,
      name: "Freund Friedrich",
      number: "+49 123456789",
      image: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1071637"
    ),
    a!map(
      id: 5,
      name: "Sohn Sebastian",
      number: "+49 123456789",
      image: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1071631"
    ),
    a!map(
      id: 6,
      name: "Tochter Theresa",
      number: "+49 123456789",
      image: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1071655"
    ),
  },
  local!recentCalls: {
    a!map(
      id: 1,
      contactId: 2,
      date: today()-2
    ),
    a!map(
      id: 2,
      contactId: 4,
      date: today()-3
    ),
    a!map(
      id: 3,
      contactId: 5,
      date: today()-5
    ),
    a!map(
      id: 4,
      contactId: 2,
      date: today()-5
    ),
    a!map(
      id: 5,
      contactId: 1,
      date: today()-7
    ),
    a!map(
      id: 6,
      contactId: 2,
      date: today()-12
    ),
    a!map(
      id: 7,
      contactId: 3,
      date: today()-14
    ),
    a!map(
      id: 8,
      contactId: 2,
      date: today()-23
    )
  },

  #"SYSTEM_SYSRULES_headerContentLayout"(
    header: #"SYSTEM_SYSRULES_cardLayout"(
      contents: {
        /*Top Element*/
        #"SYSTEM_SYSRULES_sideBySideLayout"(
          items: {
            #"SYSTEM_SYSRULES_sideBySideItem"(
              item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                labelPosition: "COLLAPSED",
                value: {
                  "   ",
                  #"SYSTEM_SYSRULES_richTextIcon"(
                    icon: "reply",
                    link: #"SYSTEM_SYSRULES_dynamicLink"(
                      value: null,
                      saveInto: ri!function
                    ),
                    linkStyle: "STANDALONE",
                    color: "#000000",
                    size: "LARGE_PLUS"
                  )
                }
              )
            ),
            #"SYSTEM_SYSRULES_sideBySideItem"(
              item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                labelPosition: "COLLAPSED",
                value: {
                  #"SYSTEM_SYSRULES_richTextItem_v1"(
                    text: "TELEFON",
                    size: "LARGE"
                  )
                }
              ),
              width: "MINIMIZE"
            ),
            #"SYSTEM_SYSRULES_sideBySideItem"(
              item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                labelPosition: "COLLAPSED",
                value: {
                  #"SYSTEM_SYSRULES_richTextIcon"(
                    icon: "phone",
                    color: "",
                    size: "EXTRA_LARGE"
                  )
                },
                align: "RIGHT"
              ),
              width: "MINIMIZE"
            )
          },
          alignVertical: "MIDDLE"
        )
      },
      style: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1063213"[3],
      showBorder: false
    ),
    contents: #"SYSTEM_SYSRULES_columnsLayout"(
      columns: {
        /*Spacing Column*/
        #"SYSTEM_SYSRULES_columnLayout"(width: "EXTRA_NARROW"),
        /*Contacts / Phonebook*/
        #"SYSTEM_SYSRULES_columnLayout"(
          width: "2X",
          contents: {
            #"SYSTEM_SYSRULES_sideBySideLayout"(
              marginAbove: "MORE",
              items: {
                #"SYSTEM_SYSRULES_sideBySideItem"(
                  item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                    label: "Kontaktliste",
                    labelPosition: "COLLAPSED",
                    value: {
                      #"SYSTEM_SYSRULES_richTextIcon"(
                        icon: "address-book-o",
                        size: "LARGE"
                      ),
                      #"SYSTEM_SYSRULES_richTextItem_v1"(
                        text: " Kontaktliste",
                        style: "STRONG",
                        size: "LARGE"
                      )
                    }
                  )
                ),
                #"SYSTEM_SYSRULES_sideBySideItem"(
                  item: #"SYSTEM_SYSRULES_ButtonArrayLayout"(
                    align: "END",
                    buttons: #"SYSTEM_SYSRULES_buttonWidget_v1"(
                      label: "Neuen Kontakt Beantragen",
                      color: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1063213"[3],
                      style: "SOLID",
                      icon: "plus"
                    )
                  )
                )
              }
            ),
            #"SYSTEM_SYSRULES_cardGroupLayout"(
              cards: #"SYSTEM_SYSRULES_forEach"(
                items: local!contacts,
                expression: #"SYSTEM_SYSRULES_cardLayout"(
                  shape: "ROUNDED",
                  marginAbove: "LESS",
                  contents: {
                    #"SYSTEM_SYSRULES_sideBySideLayout"(
                      items: {
                        #"SYSTEM_SYSRULES_sideBySideItem"(
                          width: "MINIMIZE",
                          item: #"SYSTEM_SYSRULES_imageField_v1"(
                            style: "AVATAR",
                            images: #"SYSTEM_SYSRULES_documentImage"(
                              document: fv!item.image,
                            )
                          )
                        ),
                        #"SYSTEM_SYSRULES_sideBySideItem"(
                          item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                            marginAbove: "STANDARD",
                            align: "LEFT",
                            value:{
                              #"SYSTEM_SYSRULES_richTextItem_v1"(
                                text: fv!item.name,
                                style: "STRONG",
                                size: "MEDIUM_PLUS"
                              ),
                              char(10),
                              #"SYSTEM_SYSRULES_richTextItem_v1"(
                                text: fv!item.number,
                                size: "MEDIUM"
                              )
                            }
                          ),
                        ),
                        #"SYSTEM_SYSRULES_sideBySideItem"(),
                        #"SYSTEM_SYSRULES_sideBySideItem"(
                          width: "MINIMIZE",
                          item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                            marginAbove: "STANDARD",
                            align: "CENTER",
                            value: {
                              #"SYSTEM_SYSRULES_richTextIcon"(
                                caption: "Rufe " & fv!item.name & " an",
                                size: "LARGE_PLUS",
                                icon: "phone",
                                color: "POSITIVE",
                                link: #"SYSTEM_SYSRULES_dynamicLink"(),
                                linkStyle: "STANDALONE"
                              ), "    "
                            }
                          )
                        )
                      }
                    )
                  }
                )
              )
            )
          }
        ),
        /*Recent Calls*/
        #"SYSTEM_SYSRULES_columnLayout"(
          width: "1X",
          contents: {
            #"SYSTEM_SYSRULES_richTextDisplayField"(
              marginAbove: "MORE",
              label: "Deine letzten Anrufe",
              labelPosition: "COLLAPSED",
              value: {
                #"SYSTEM_SYSRULES_richTextIcon"(
                  icon: "headset",
                  size: "LARGE"
                ),
                #"SYSTEM_SYSRULES_richTextItem_v1"(
                  text: " Deine letzten Anrufe",
                  style: "STRONG",
                  size: "LARGE"
                )
              }
            ),
            #"SYSTEM_SYSRULES_forEach"(
              items: local!recentCalls,
              expression: #"SYSTEM_SYSRULES_cardLayout"(
                shape: "ROUNDED",
                marginAbove: "LESS",
                style: "#505050",
                showBorder: false,
                contents: {
                  #"SYSTEM_SYSRULES_sideBySideLayout"(
                    items: {
                      #"SYSTEM_SYSRULES_sideBySideItem"(
                        width: "MINIMIZE",
                        item: #"SYSTEM_SYSRULES_imageField_v1"(
                          size: "EXTRA_SMALL",
                          style: "AVATAR",
                          images: #"SYSTEM_SYSRULES_documentImage"(
                            document: index(local!contacts.image, wherecontains(fv!item.contactId, local!contacts.id), null),
                          )
                        )
                      ),
                      #"SYSTEM_SYSRULES_sideBySideItem"(
                        item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                          marginAbove: "STANDARD",
                          align: "LEFT",
                          value:{
                            #"SYSTEM_SYSRULES_richTextItem_v1"(
                              text: index(local!contacts.name, wherecontains(fv!item.contactId, local!contacts.id), null),
                              style: "STRONG",
                              size: "MEDIUM"
                            ),
                            char(10),
                            #"SYSTEM_SYSRULES_richTextItem_v1"(
                              text: fv!item.number,
                              size: "MEDIUM"
                            )
                          }
                        ),
                      ),
                      #"SYSTEM_SYSRULES_sideBySideItem"(),
                      #"SYSTEM_SYSRULES_sideBySideItem"(
                        width: "MINIMIZE",
                        item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                          marginAbove: "STANDARD",
                          align: "CENTER",
                          value: {
                            #"SYSTEM_SYSRULES_richTextItem_v1"(
                              text: "Angerufen am: ",
                            ),
                            #"SYSTEM_SYSRULES_richTextItem_v1"(
                              text: fv!item.date,
                            )
                          }
                        )
                      )
                    }
                  )
                }
              )
            )
          }
        ),
        /*Spacing Column*/
        #"SYSTEM_SYSRULES_columnLayout"(width: "EXTRA_NARROW")
      }
    ),
    backgroundColor: "#111111",
    contentsPadding: "NONE"
  ),
)
